script:
frappe.ui.form.on('Assign Class to Teacher', {
    teacher: function(frm) {
        if (frm.doc.teacher) {
            frappe.db.get_value('Teacher', frm.doc.teacher, 'full_name', function(r) {
                if (r && r.full_name) {
                    frm.set_value('teacher_name', r.full_name);
                }
            });
        } else {
            frm.set_value('teacher_name', '');
        }
    }
});
